import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F14: 負債結構與償債壓力測試","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F14_負債結構與償債壓力測試.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F14_負債結構與償債壓力測試.md"}'),l={name:"審計報告庫/財務審計/6442_光聖/20260504/F14_負債結構與償債壓力測試.md"};function i(n,a,h,s,d,_){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="f14-負債結構與償債壓力測試" tabindex="-1">F14: 負債結構與償債壓力測試 <a class="header-anchor" href="#f14-負債結構與償債壓力測試" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：負債比 49% 多為 CB 非現金償債壓力，利息保障倍數 69 倍，現金 74.9 億完全覆蓋總負債 65.9 億，實質淨現金狀態償債能力極強。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：2025 年報</li></ul><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>負債結構：流動負債 40 億（短借 0 + 應付 13.1 億 + 稅負 3.5 億），非流動負債 25.9 億（CB 23.5 億）。利息保障倍數 69 倍（EBIT 25.8 億 / 利息 0.37 億）。利率敏感度：利息每升 1%，僅增加 0.37 億利息支出，影響 EPS 不到 0.5 元。負債比 49% 雖較 2023 年 38.7% 上升，但主因為 CB 發行，屬結構性調整。</p><p><strong>評級：S（優）</strong> — 現金充足覆蓋全部債務，利息風險極低。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>槓桿水位：</strong> 淨債務 = 總負債 65.9 億 − 現金 74.9 億 = −9 億（淨現金狀態）。資產負債表穿透後無淨負債，利息保障倍數以營益 25.39 億對比利息 0.37 億達 69 倍，融資結構極為穩健。</p><p><strong>短期流動性：</strong> 現金 74.9 億 / 流動負債 40 億 = 187%，速動資產 95.3 億（含高流動性金融資產） / 流動負債 40 億 = 238%。即使所有流動負債同時到期，也能以現金全額清償 1.87 次。營運資金（流動資產−流動負債）約 84.5 億，緩衝空間充足。</p><p><strong>CB 壓力分析：</strong> 23.5 億 CB 為最大潛在負債變數。若全數轉換將稀釋 40-50%，但利息節省使稀釋影響部分抵銷。若全數贖回，74.9 億現金足以支付，且贖回後淨現金增至 51.4 億。關鍵觀察點為轉換價格與股價溢價狀況，2025 年底轉換價格尚低於市價，轉換可能性偏高。</p><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li>CB 23.5 億若全數轉換，將新增約 3,000-4,000 萬股，EPS 稀釋幅度達 40-50%，從 23.46 元降至 16-18 元，股權稀釋對現有股東的影響不可忽視。</li><li>負債比從 2023 年 38.7% 升至 2025 年 49.0%，雖仍屬安全但趨勢向上。若未來再發行 CB 或銀行借款擴產，負債比可能突破 55%，屆時財務結構將不再具有壓倒性優勢。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li>淨現金狀態（現金 74.9 億 &gt; 總負債 65.9 億）在台股電子製造業中極為罕見，提供最大的財務彈性，可隨時因應景氣波動或把握策略併購機會。</li><li>利息保障倍數 69 倍是台股製造業最高水準之一，利率波動對獲利的影響微乎其微。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>償債能力無虞，核心風險在於 CB 轉換對股權的稀釋效應，需關注轉換價與市價的差距。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind TaiwanStockBalanceSheet</li><li>年報資料：6442 2025 Q4 合併財報第 35 頁（借款明細）</li><li>數據查詢日期：2026-05-04</li></ul>',23)])])}const p=e(l,[["render",i]]);export{u as __pageData,p as default};
